sql:
SELECT zone_name, AVG(connection_points) AS Average_Connection_Points
FROM transmission_zones
GROUP BY zone_name;

SELECT zone_id, zone_name, location, connection_points 
FROM transmission_zones
WHERE connection_points = (SELECT MAX(connection_points) FROM transmission_zones);

SELECT zone_id, AVG(load_mw) AS average_load
FROM real_time_data
GROUP BY zone_id;

SELECT *
FROM transmission_zones
WHERE zone_status = 'active' AND connection_points > 3;

external_knowledge:
- 'High Voltage' refers to the type of transmission zones that operate at significantly elevated electrical potentials; 
- 'Winter' is represented by the period during which days are shorter and temperatures are lower, often impacting energy demand and supply; 
- 'New' in the context of capacity type signifies recent or newly installed transmission capabilities.

- "grid areas" refers to transmission zones;
- "identifiers" refer to the unique `zone_id` values that define each transmission zone;
- "number of lines" represents the count of transmission lines associated with each grid area or transmission zone.

sql:
SELECT AVG(cost_impact) AS average_cost_impact
FROM scenario_planning
WHERE cost_impact > (SELECT AVG(cost_impact) FROM scenario_planning);

SELECT tz.zone_name, tz.zone_status, tc.transmission_cost, tc.cost_category
FROM transmission_zones tz
JOIN transmission_costs tc ON tz.zone_id = tc.zone_id;

SELECT capacity_type, COUNT(*) AS total_capacities 
FROM transmission_capacities 
GROUP BY capacity_type;

SELECT AVG(transmission_cost) 
FROM transmission_costs 
WHERE zone_id = 'your_zone_id';

SELECT COUNT(*) 
FROM transmission_zones
WHERE zone_status = 'active';
